import{_ as t,o as a,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"136. Professional Development Leave","description":"","frontmatter":{"title":"136. Professional Development Leave","eba":"Mental Health Services 2024-2028","topics":["leave","preliminary","education-pd"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/education-pd/136-professional-development-leave.md","filePath":"ebas/mental-health/health-professionals/education-pd/136-professional-development-leave.md"}'),i={name:"ebas/mental-health/health-professionals/education-pd/136-professional-development-leave.md"};function s(r,e,l,p,d,h){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_136-professional-development-leave" tabindex="-1">136. Professional Development Leave <a class="header-anchor" href="#_136-professional-development-leave" aria-label="Permalink to &quot;136. Professional Development Leave&quot;">​</a></h1><p><strong>136.1</strong> Entitlement</p><p><strong>(a)</strong> A full-time Employee is entitled to five days’ paid professional development leave per year, in addition to other prescribed leave entitlements. Part time Employees will have a pro rata entitlement</p><p><strong>(b)</strong> The leave is cumulative over two calendar years.</p><p><strong>136.2</strong> Application</p><p><strong>(a)</strong> To access the benefits of this provision it is the responsibility of the Employee to make an application for this leave.</p><p><strong>(b)</strong> An application for this leave, nominating the preferred date(s) will be made in writing to the Manager providing a brief description of the nature of the professional development activity to be undertaken and its applicability to the Employee’s profession. The application may be utilised for, but not limited to, research, home study, attendance at seminars and conferences. An Employee may be required to report back on the seminar or conference.</p><p><strong>(c)</strong> The application must be made at least six weeks prior to the requested date(s) and shall be approved by the Manager unless there are exceptional circumstances that exist that justify non-approval. The applicant will be notified in writing if the leave is approved or not within seven (7) days of the request being made. If leave is not granted the reasons will be included in the notification to the applicant.</p><p><strong>136.3</strong> Intentional Peer Support Training (ONLY LLEW)</p><p><strong>(a)</strong> Subject to course availability, it is the intention of this clause that all LLEW Employees will be provided with paid leave to complete IPS Core Training, or equivalent, as soon as practicable, after the commencement of their employment.</p><p><strong>(b)</strong> An application for this leave, nominating the preferred date(s) will be made in writing to the Manager/Supervisor. The application must be made at least four (4) weeks prior to the requested date(s).</p><p><strong>(c)</strong> The Employer will approve an application for leave under this sub-clause unless there are exceptional circumstances that exist that justify non-approval. The applicant will be notified in writing if the leave is approved or not within seven (7) days of the request being made. If leave is not granted the reason will be included in the notification to the applicant.</p><p><strong>(d)</strong> Leave taken under this sub-clause will be in addition to the entitlement at 136.1.</p>',13)])])}const f=t(i,[["render",s]]);export{m as __pageData,f as default};
